mapper.select:
SELECT 
FROM domain_package_validation_result
WHERE version_id = #{versionId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
  AND job_id = #{jobId, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}

mapper.update:
UPDATE domain_package_validation_result
SET status = #{newStatus, typeHandler=com.pdp.persistence.typehandler.StringEnumTypeHandler},
    passed = #{passed},
    validated_at = #{now, typeHandler=com.pdp.persistence.typehandler.InstantTypeHandler}
WHERE id = #{id, typeHandler=com.pdp.persistence.typehandler.UuidBinaryTypeHandler}
